const std = @import("std");

pub fn build(b: *std.Build) !void {
    const target = b.standardTargetOptions(.{});
    const optimize = b.standardOptimizeOption(.{});

    const upstream = b.dependency("wolfssl", .{});
    const lib = b.addStaticLibrary(.{
        .name = "wolfssl",
        .target = target,
        .optimize = optimize,
    });

    lib.installHeadersDirectory(upstream.path(""), "", .{});
    lib.installHeadersDirectory(upstream.path("wolfssl"), "", .{});

    lib.linkLibC();

    lib.addIncludePath(upstream.path(""));
    lib.addCSourceFiles(.{
        .root = upstream.path(""),
        .files = &.{
            "src/bio.c",
            "src/conf.c",
            "src/crl.c",
            "src/dtls.c",
            "src/dtls13.c",
            "src/internal.c",
            "src/keys.c",
            "src/ocsp.c",
            "src/pk.c",
            "src/quic.c",
            "src/sniffer.c",
            "src/ssl.c",
            "src/ssl_asn1.c",
            "src/ssl_bn.c",
            "src/ssl_certman.c",
            "src/ssl_crypto.c",
            "src/ssl_load.c",
            "src/ssl_misc.c",
            "src/ssl_p7p12.c",
            "src/ssl_sess.c",
            "src/tls.c",
            "src/tls13.c",
            "src/wolfio.c",
            "src/x509.c",
            "src/x509_str.c",
            "wolfcrypt/src/aes.c",
            "wolfcrypt/src/arc4.c",
            "wolfcrypt/src/ascon.c",
            "wolfcrypt/src/asm.c",
            "wolfcrypt/src/asn.c",
            "wolfcrypt/src/blake2b.c",
            "wolfcrypt/src/blake2s.c",
            "wolfcrypt/src/camellia.c",
            "wolfcrypt/src/chacha.c",
            "wolfcrypt/src/chacha20_poly1305.c",
            "wolfcrypt/src/cmac.c",
            "wolfcrypt/src/coding.c",
            "wolfcrypt/src/compress.c",
            "wolfcrypt/src/cpuid.c",
            "wolfcrypt/src/cryptocb.c",
            "wolfcrypt/src/curve25519.c",
            "wolfcrypt/src/curve448.c",
            "wolfcrypt/src/des3.c",
            "wolfcrypt/src/dh.c",
            "wolfcrypt/src/dilithium.c",
            "wolfcrypt/src/dsa.c",
            "wolfcrypt/src/ecc.c",
            "wolfcrypt/src/ecc_fp.c",
            "wolfcrypt/src/eccsi.c",
            "wolfcrypt/src/ed25519.c",
            "wolfcrypt/src/ed448.c",
            "wolfcrypt/src/error.c",
            "wolfcrypt/src/evp.c",
            "wolfcrypt/src/ext_lms.c",
            "wolfcrypt/src/ext_mlkem.c",
            "wolfcrypt/src/ext_xmss.c",
            "wolfcrypt/src/falcon.c",
            "wolfcrypt/src/fe_448.c",
            "wolfcrypt/src/fe_low_mem.c",
            "wolfcrypt/src/fe_operations.c",
            "wolfcrypt/src/ge_448.c",
            "wolfcrypt/src/ge_low_mem.c",
            "wolfcrypt/src/ge_operations.c",
            "wolfcrypt/src/hash.c",
            "wolfcrypt/src/hmac.c",
            "wolfcrypt/src/hpke.c",
            "wolfcrypt/src/integer.c",
            "wolfcrypt/src/kdf.c",
            "wolfcrypt/src/logging.c",
            "wolfcrypt/src/md2.c",
            "wolfcrypt/src/md4.c",
            "wolfcrypt/src/md5.c",
            "wolfcrypt/src/memory.c",
            "wolfcrypt/src/misc.c",
            "wolfcrypt/src/pkcs12.c",
            "wolfcrypt/src/pkcs7.c",
            "wolfcrypt/src/poly1305.c",
            "wolfcrypt/src/pwdbased.c",
            "wolfcrypt/src/random.c",
            "wolfcrypt/src/rc2.c",
            "wolfcrypt/src/ripemd.c",
            "wolfcrypt/src/rsa.c",
            "wolfcrypt/src/sakke.c",
            "wolfcrypt/src/sha.c",
            "wolfcrypt/src/sha256.c",
            "wolfcrypt/src/sha3.c",
            "wolfcrypt/src/sha512.c",
            "wolfcrypt/src/signature.c",
            "wolfcrypt/src/siphash.c",
            "wolfcrypt/src/sm2.c",
            "wolfcrypt/src/sm3.c",
            "wolfcrypt/src/sm4.c",
            "wolfcrypt/src/sp_arm32.c",
            "wolfcrypt/src/sp_arm64.c",
            "wolfcrypt/src/sp_armthumb.c",
            "wolfcrypt/src/sp_c32.c",
            "wolfcrypt/src/sp_c64.c",
            "wolfcrypt/src/sp_cortexm.c",
            "wolfcrypt/src/sp_dsp32.c",
            "wolfcrypt/src/sp_int.c",
            "wolfcrypt/src/sp_sm2_arm32.c",
            "wolfcrypt/src/sp_sm2_arm64.c",
            "wolfcrypt/src/sp_sm2_armthumb.c",
            "wolfcrypt/src/sp_sm2_c32.c",
            "wolfcrypt/src/sp_sm2_c64.c",
