            "wolfcrypt/src/sphincs.c",
            "wolfcrypt/src/srp.c",
            "wolfcrypt/src/tfm.c",
            "wolfcrypt/src/wc_dsp.c",
            "wolfcrypt/src/wc_encrypt.c",
            "wolfcrypt/src/wc_lms.c",
            "wolfcrypt/src/wc_lms_impl.c",
            "wolfcrypt/src/wc_mlkem.c",
            "wolfcrypt/src/wc_mlkem_poly.c",
            "wolfcrypt/src/wc_pkcs11.c",
            "wolfcrypt/src/wc_port.c",
            "wolfcrypt/src/wc_xmss.c",
            "wolfcrypt/src/wc_xmss_impl.c",
            "wolfcrypt/src/wolfevent.c",
            "wolfcrypt/src/wolfmath.c",
        },
        .flags = &.{
            "-DHAVE_ECC",
            "-DTFM_ECC256",
            "-DHAVE_CHACHA",
            "-DHAVE_HASHDRBG",
            "-DHAVE_TLS_EXTENSIONS",
            "-DHAVE_SUPPORTED_CURVES",
            "-DHAVE_EXTENDED_MASTER",
            "-DHAVE_ENCRYPT_THEN_MAC",
            "-DWOLFSSL_POST_HANDSHAKE_AUTH",
            "-DTFM_TIMING_RESISTANT",
            "-DWOLFSSL_USE_ALIGN",
            "-DECC_TIMING_RESISTANT",
            "-DOPENSSL_ALL",
            "-DWOLFSSL_EITHER_SIDE",
            "-DWC_RSA_NO_PADDING",
            "-DWC_RSA_PSS",
            "-DWOLFSSL_PSS_LONG_SALT",
            "-DWOLFSSL_TICKET_HAVE_ID",
            "-DWOLFSSL_ERROR_CODE_OPENSSL",
            "-DWOLFSSL_CERT_NAME_ALL",
        },
    });

    b.installArtifact(lib);
}
